const bulan_no = parseInt($json.bulan_no);
const tahun = String($json.tahun || '2026');

if (!bulan_no || bulan_no < 1 || bulan_no > 12) {
  throw new Error('Bulan tidak valid: ' + bulan_no + '. Set bulan_no = 1..12 di node Input Form.');
}

const no = String(bulan_no).padStart(2, '0');
const nama = bulan_names[bulan_no - 1];

return [{
  json: {
    query: `${no}. ${nama} ${tahun}`,
    bulan_str: nama.toLowerCase(),
    bulan_no_str: no,
    bulan_nama: nama,
    tahun_str: tahun
  }
}];

