    full_name: `${bulan_no_str}. ${bulan_nama} ${tahun_str} ${o.no}. ${o.name.toUpperCase()}`
  }
}));

// Filter SO Files: ambil 1 file terbaru per outlet
const items = $input.all();
const query = $('Build Search Query').first().json.query.toLowerCase();

// Daftar outlet dari inventory
const outletNames = [
  'taplau','air tawar','gunung pangilun','belibis','siteba',
  'pasar baru','tunggul hitam','anduring','jati','air pacah',
  'lubuk begalung','balai baru','cendrawasih','seberang padang','bandar buat',
  'air dingin','tabing','belimbing','rawang','lubuk buaya',
  'parak laweh','lubuk lintah','kasang','bungus','lubuk alung',
  'kurai taji','lohong','manggung','pauh kambar','sicincin',
  'tanah garam','selayo','gunung talang','sungai sariak','simpang rumbio'
];

const outletMap = {};

for (const item of items) {
  const name = (item.json.name || '').trim().toLowerCase();

  // 1. Harus mengandung bulan+tahun (misal '07. juli 2026')
  if (!name.includes(query)) continue;

  // 2. Tentukan nomor outlet
  let matchedOutlet = null;
  for (let i = 0; i < outletNames.length; i++) {
    if (name.includes(outletNames[i])) {
      matchedOutlet = String(i + 1).padStart(2, '0');
      break;
    }
  }

  // Jika tidak cocok nama, coba cari angka outlet-nya (fallback)
  if (!matchedOutlet) {
    const nums = name.match(/\b\d{1,2}\b/g);
    if (nums) {
      matchedOutlet = nums[nums.length - 1].padStart(2, '0');
    }
  }

  if (!matchedOutlet) continue;

  // 3. Simpan hanya 1 file terbaru (karena Google Drive Search sudah mengurutkan modifiedTime desc)
  if (!outletMap[matchedOutlet]) {
    outletMap[matchedOutlet] = item;
  }
}

const filtered = Object.values(outletMap);
console.log(`Filter: ${items.length} total → ${filtered.length} outlet SO files (1 per outlet)`);
return filtered;

// Kumpulkan semua binary xlsx dari Download Sheet (35 items) jadi 1 item
const items = $input.all();
const mergedBinary = {};
const keys = [];
let count = 0;

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.binary) continue;
  for (const key of Object.keys(item.binary)) {
    const b = item.binary[key];
    // Pastikan nama file adalah nama asli dari Google Drive (agar ada nomor outlet-nya)
    let namaFile = item.json.name || b.fileName || `so_file_${i}`;
    if (!namaFile.toLowerCase().endsWith('.xlsx')) namaFile += '.xlsx';
    b.fileName = namaFile;

    const safeKey = `f${String(i).padStart(2,'0')}`;
    mergedBinary[safeKey] = b;
    keys.push(safeKey);
    count++;
  }
}

if (count === 0) throw new Error('Tidak ada binary! Pastikan Download Sheet berhasil.');

console.log(`Collected ${count} files â†’ keys: ${keys.join(',')}`);

return [{
  json: {
    so_file_count: count,
    binary_keys: keys.join(',')
  },
  binary: mergedBinary
}];
